sql:
SELECT r.name
FROM researchers r
WHERE (
    SELECT COUNT(*) 
    FROM speeches s
) = (
    SELECT COUNT(*) 
    FROM speech_analysis sa 
    WHERE sa.researcher_id = r.researcher_id
);

SELECT speaker, content
FROM speeches
ORDER BY speech_date ASC;

SELECT speeches.*, speech_sentiment.sentiment_score, speech_sentiment.sentiment_category 
FROM speeches 
INNER JOIN speech_sentiment ON speeches.speech_id = speech_sentiment.speech_id;

SELECT speeches.speaker, parties.party_name, speeches.sentiment_score
FROM speeches
JOIN parties ON speeches.party_id = parties.party_id;
